// Unit 4: Im Supermarkt
// Level: A1

const UNIT_4 =
{n:4,lang:"de",srcLang:"en",track:"v2",title:"Im Supermarkt",sub:"Shopping, food & the accusative case",icon:"🛒",level:"A1.1",color:"#7B5EE8",lessons:[

// ─── L1: Einkaufswagen-Panik ───
{id:"deu_r4l1",title:"Einkaufswagen-Panik",icon:"🛒",xp:15,board:true,steps:[
{type:"intro",title:"Speed Checkout Survival",desc:"Verumius enters a German supermarket for the first time. Shopping carts need a coin. Cashiers don't bag. Cash is king. Survival starts now.",goals:["Shopping vocabulary","Money words and payment","Navigate a German supermarket"]},
{type:"story",speaker:"narrator",mood:"cinematic",art:"de-rewe-entrance",trg:"REWE. Rote Buchstaben. Automatische Türen. Verumius steht davor mit einer leeren Stofftasche. Nein, Moment. Ohne Stofftasche. Ohne alles.",src:"REWE. Red letters. Automatic doors. Verumius stands in front with an empty cloth bag. No, wait. Without a cloth bag. Without anything."},
{type:"story",speaker:"verumius",mood:"confused",art:"de-rewe-cart-chain",trg:"Die Einkaufswagen. Sie sind... zusammen? Mit einer Kette? Ich ziehe. Und ziehe. Nichts passiert.",src:"The shopping carts. They are... together? With a chain? I pull. And pull. Nothing happens."},
{type:"story",speaker:"narrator",mood:"amused",art:"de-rewe-coin-slot",trg:"Eine alte Frau geht vorbei. Sie steckt eine Münze in den Schlitz. Klick. Ihr Wagen ist frei. Verumius hat keine Münze. Er hat einen Fünfzig-Euro-Schein.",src:"An old woman walks past. She puts a coin in the slot. Click. Her cart is free. Verumius has no coin. He has a fifty-euro bill."},
{type:"story",speaker:"verumius",mood:"defeated",art:"de-rewe-pfand-machine",trg:"Was ist diese Maschine? Grüne Lichter. Ein Loch für Flaschen. Vielleicht... ein Spiel? Ein Automat? Ich habe keine Flasche. Ich habe nichts.",src:"What is this machine? Green lights. A hole for bottles. Maybe... a game? A machine? I have no bottle. I have nothing."},
{type:"teach",trg:"einkaufen",src:"to shop / go grocery shopping",note:"Separable: ich kaufe ein, du kaufst ein.",example:"A: Wo kaufst du ein?\nB: Ich kaufe im Supermarkt ein.",exampleSrc:"A: Where do you shop?\nB: I shop at the supermarket.",funFact:"Germans plan grocery trips like military operations. List, bags, coins for the cart. No impulse buying. Hildi would approve."},
{type:"teach",trg:"der Kunde / die Kundin",src:"the customer (m/f)",note:"Masculine: der Kunde. Feminine: die Kundin.",example:"A: Sind Sie Kunde hier?\nB: Ja, ich bin Kundin.",exampleSrc:"A: Are you a customer here?\nB: Yes, I am a customer.",funFact:"German always has male + female forms for people: Kunde/Kundin, Verkäufer/Verkäuferin. The gendered forms are standard."},
{type:"teach",trg:"die Kasse",src:"the checkout / register",note:"Feminine. Where you pay.",example:"A: Wo ist die Kasse?\nB: Die Kasse ist dort hinten.",exampleSrc:"A: Where is the checkout?\nB: The checkout is back there.",funFact:"German cashiers sit down. They will NEVER bag your groceries. You bag. Fast. While the next customer's items are already on the belt."},
{type:"teach",trg:"der Verkäufer",src:"the salesperson",note:"Masculine. Feminine: die Verkäuferin.",example:"A: Der Verkäufer ist nett.\nB: Ja, er hilft mir.",exampleSrc:"A: The salesperson is nice.\nB: Yes, he is helping me.",funFact:"Literally 'the seller.' German loves compound transparency. Ver+käufer from ver+kaufen."},
{type:"teach",trg:"der Preis",src:"the price",note:"Masculine. Plural: die Preise.",example:"A: Wie ist der Preis?\nB: Der Preis ist gut.",exampleSrc:"A: How is the price?\nB: The price is good.",funFact:"'Preis' sounds like 'price' because it IS the same Germanic root. Preiswert = price-worthy = good value."},
{type:"teach",trg:"bezahlen",src:"to pay (for something)",note:"Regular. Also: zahlen = to pay (in general).",example:"A: Ich möchte bezahlen.\nB: Bar oder mit Karte?",exampleSrc:"A: I would like to pay.\nB: Cash or card?",funFact:"'Bezahlen' = pay for something specific. 'Zahlen' = pay in general. Both work at the register. 'Zahlen, bitte!' = check, please!"},
{type:"teach",trg:"das Geld",src:"the money",note:"Neuter. Also: der Euro, der Cent.",example:"A: Hast du Geld?\nB: Ja, ich habe zwanzig Euro.",exampleSrc:"A: Do you have money?\nB: Yes, I have twenty euros.",funFact:"Euro coins show different countries on the back. German euros have the Brandenburg Gate, an eagle, or an oak leaf. Collect them all!"},
{type:"teach",trg:"die Kreditkarte",src:"the credit card",note:"Feminine. Many German shops still don't accept them!",example:"A: Nehmen Sie Kreditkarte?\nB: Nein, nur bar.",exampleSrc:"A: Do you accept credit card?\nB: No, cash only.",funFact:"Many German shops STILL don't take cards. Cash is king. Always carry Bargeld. The Bäckerei, the Kiosk, the Döner stand: bar only."},
{type:"teach",trg:"kaufen",src:"to buy",note:"Regular. Opposite: verkaufen (to sell).",example:"A: Ich kaufe Brot.\nB: Der Laden verkauft gutes Brot.",exampleSrc:"A: I buy bread.\nB: The shop sells good bread.",funFact:"Kauf = buy. Ver+kauf = sell. The ver- prefix flips meaning. Like mieten/vermieten from Unit 3."},
{type:"teach",trg:"das Angebot",src:"the offer / special deal",note:"Neuter. Also: die Tasche (bag), der Schuh (shoe), die Jacke (jacket).",example:"A: Das Angebot ist gut!\nB: Ja, sehr günstig.",exampleSrc:"A: The offer is great!\nB: Yes, very good value.",funFact:"'Sonderangebot' = special offer. Germans plan shopping around Angebote. The weekly flyer is sacred. Hildi has a filing system."},
{type:"teach",trg:"die Rechnung",src:"the bill / receipt",note:"Feminine. Also: der Automat (machine).",example:"A: Kann ich die Rechnung haben?\nB: Hier, bitte.",exampleSrc:"A: Can I have the bill?\nB: Here you go.",funFact:"'Automat' = any machine: Kaffeeautomat, Parkscheinautomat, Pfandautomat (bottle deposit machine). Germans automate everything."},
{type:"teach",trg:"die Kleidung",src:"the clothing",note:"Feminine. Collective noun, always singular.",example:"A: Ich brauche neue Kleidung.\nB: Die Kleidung ist teuer.",exampleSrc:"A: I need new clothes.\nB: The clothing is expensive.",funFact:"Like Obst and Gemüse, Kleidung is always singular. For individual items: der Schuh (shoe), die Jacke (jacket), die Tasche (bag)."},
{type:"tip",title:"Story Setup",text:"Verumius stands outside REWE.\nHe needs a Euro coin for the Einkaufswagen (shopping cart).\nHe has only a 50-Euro bill.\nThe Pfandautomat blinks at him.\n\nPfand = bottle deposit. Germans return bottles to machines for money.\nEvery bottle has a Pfand value (8-25 cents).\nThe adventure begins."},
{type:"mc",q:"Verumius asks 'Nehmen Sie Kreditkarte?' The cashier says 'Nein.' What must he use?",opts:["eine App","einen Scheck","eine Überweisung","Bargeld (cash)"],ans:"Bargeld (cash)",hint:"Many German shops only accept one form of payment. Not plastic."},
{type:"fb",s:"Das {1} ist gut! Ich kaufe die Jacke.",a:["Angebot"],opts:["Angebot","Geld","Preis","Kasse"],hint:"A special deal or discount that makes something cheaper than usual.",sSrc:"The offer is good! I am buying the jacket."},
{type:"match",pairs:[{trg:"einkaufen",src:"to shop"},{trg:"bezahlen",src:"to pay"},{trg:"der Preis",src:"price"},{trg:"die Kasse",src:"checkout"},{trg:"das Geld",src:"money"}]},
{type:"mc",q:"'Lebensmittel' literally means:",opts:["means of life","food store","daily shopping","fresh goods"],ans:"means of life",hint:"Translate each part of this compound noun separately."},
{type:"story",speaker:"narrator",mood:"wry",art:"de-rewe-basket",trg:"Verumius nimmt einen Korb. Wie ein Tourist. Kein Wagen, keine Münze, keine Tüte. Aber Mut. Den hat er.",src:"Verumius grabs a basket. Like a tourist. No cart, no coin, no bag. But courage. That he has."}
]},

// ─── L2: Obst, Gemüse und Chaos ───
{id:"deu_r4l2",title:"Obst, Gemüse und Chaos",icon:"🍎",xp:15,board:true,steps:[
{type:"intro",title:"Obst, Gemüse und Chaos",desc:"The produce aisle. 22 food words and 10 drink words, each with its article. Germany has 3,200 bread varieties. UNESCO agrees.",goals:["22 food words with gender","10 drink words with gender","Master der/die/das for food"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-rewe-produce",trg:"Die Obstabteilung. Farben wie ein Gemälde. Verumius kennt kein Wort dafür. Rote Dinge. Gelbe Dinge. Grüne Dinge. Alles sieht gut aus.",src:"The produce section. Colors like a painting. Verumius knows no word for any of it. Red things. Yellow things. Green things. Everything looks good."},
{type:"teach",trg:"das Obst",src:"the fruit (collective)",note:"Neuter. ALWAYS singular. Never 'Obste.'",example:"A: Ich esse gern Obst.\nB: Welches Obst magst du?",exampleSrc:"A: I like eating fruit.\nB: Which fruit do you like?",funFact:"Obst is always singular in German. You never say 'Obste.' Same with Gemüse. German hates pluralizing categories."},
{type:"teach",trg:"der Apfel",src:"the apple",note:"Masculine. Plural: die Äpfel (umlaut!).",example:"A: Der Apfel ist rot.\nB: Ich kaufe drei Äpfel.",exampleSrc:"A: The apple is red.\nB: I am buying three apples.",funFact:"Plural changes the vowel: Apfel to Äpfel. Umlaut magic! Same pattern: Vater to Väter, Bruder to Brüder."},
{type:"teach",trg:"die Banane",src:"the banana",note:"Feminine. Also: die Birne (pear). Both start with B!",example:"A: Eine Banane, bitte.\nB: Und eine Birne?",exampleSrc:"A: A banana, please.\nB: And a pear?",funFact:"Both feminine, both fruit, both start with B. Life is easy sometimes."},
{type:"teach",trg:"die Tomate",src:"the tomato",note:"Feminine. Also: die Kartoffel (potato).",example:"A: Die Tomaten sind frisch.\nB: Und die Kartoffeln?",exampleSrc:"A: The tomatoes are fresh.\nB: And the potatoes?",funFact:"'Kartoffel' originally meant 'truffle'! Germans renamed the potato after truffles when it arrived from the Americas."},
{type:"teach",trg:"das Gemüse",src:"the vegetables (collective)",note:"Neuter. Always singular, like Obst.",example:"A: Ich brauche Gemüse.\nB: Der Salat ist im Angebot.",exampleSrc:"A: I need vegetables.\nB: The lettuce is on sale.",funFact:"Like Obst, Gemüse is always singular. German hates pluralizing categories. Der Salat = lettuce/salad."},
{type:"teach",trg:"die Gurke",src:"the cucumber",pos:"noun",gender:"f",note:"Feminine: die Gurke. Plural: die Gurken.",example:"A: Frische Gurken!\nB: Zwei für einen Euro!\nA: Ich nehme vier, bitte.",exampleSrc:"A: Fresh cucumbers!\nB: Two for one euro!\nA: I'll take four, please.",funFact:"'Saure Gurke' (sour cucumber) = pickle. In Berlin, 'Spreewaldgurken' from the Spreewald region are legendary. They even have pickle festivals."},
{type:"teach",trg:"die Zwiebel",src:"the onion",pos:"noun",gender:"f",note:"Feminine: die Zwiebel. Plural: die Zwiebeln.",example:"A: Brauchst du Zwiebeln?\nB: Ja, drei Zwiebeln bitte.",exampleSrc:"A: Do you need onions?\nB: Yes, three onions please.",funFact:"'Zwiebelkuchen' (onion cake) is a savory autumn treat in Southern Germany, always paired with 'Federweißer' (young wine). A seasonal tradition."},
{type:"tip",title:"Obst vs Gemüse",text:"Two important category words:\n\nObst = fruit (das Obst, neuter, uncountable)\nGemüse = vegetables (das Gemüse, neuter, uncountable)\n\nUse them when shopping:\nIch suche das Obst. = I am looking for the fruit section.\nHaben Sie frisches Gemüse? = Do you have fresh vegetables?\n\nNote: individual fruits use their own article (der Apfel, die Banane), but the category word Obst is always das.",deepDive:{title:"At the German Wochenmarkt",text:"Germany has vibrant weekly markets (Wochenmärkte) in almost every town and city, open on Saturday mornings.\n\nUseful phrases:\nWas kostet ein Kilo? = What does a kilo cost?\nIch hätte gern 500 Gramm. = I would like 500 grams.\nDas macht... Euro. = That comes to... euros.\n\nProduce is fresher and often cheaper than the supermarket. Bring your own bag!"}},
{type:"teach",trg:"das Brot",src:"the bread",note:"Neuter. Also: das Brötchen (bread roll).",example:"A: Ich kaufe Brot.\nB: Und Brötchen?",exampleSrc:"A: I am buying bread.\nB: And bread rolls?",funFact:"Germany has 3,200+ bread varieties. More than any country on earth. UNESCO lists German bread culture as intangible cultural heritage."},
{type:"teach",trg:"die Butter",src:"the butter",note:"Feminine. Also: das Ei (egg), das Salz (salt), das Öl (oil).",example:"A: Butter und Eier, bitte.\nB: Und Salz?",exampleSrc:"A: Butter and eggs, please.\nB: And salt?",funFact:"Ei to Eier is one of German's weird plurals. Salz and Öl are both neuter. Liquids and powders often are."},
{type:"teach",trg:"das Fleisch",src:"the meat",note:"Neuter. Also: der Fisch (fish), das Hähnchen (chicken).",example:"A: Fleisch oder Fisch?\nB: Hähnchen, bitte.",exampleSrc:"A: Meat or fish?\nB: Chicken, please.",funFact:"Hähnchen = little rooster (Hahn + chen). The diminutive -chen makes EVERYTHING neuter. Just like Mädchen."},
{type:"teach",trg:"der Schinken",src:"the ham",note:"Masculine. Also: der Kuchen (cake), der Reis (rice).",example:"A: Zweihundert Gramm Schinken, bitte.\nB: Hier, genau zweihundert.",exampleSrc:"A: Two hundred grams of ham, please.\nB: Here, exactly two hundred.",funFact:"Germans eat ham for breakfast. On bread. With butter. Every morning. The Brotzeit (bread-time) is sacred."},
{type:"teach",trg:"die Pommes frites",src:"the fries / chips",note:"Always plural (die). Germans say 'Pommes' (POMM-ess).",example:"A: Pommes mit Mayo?\nB: Ja, immer!",exampleSrc:"A: Fries with mayo?\nB: Yes, always!",funFact:"Germans say 'Pommes' (POMM-ess), never 'frites.' And yes, they put mayo on them. Ketchup is also common, but mayo is the default."},
{type:"teach",trg:"das Wasser",src:"the water",note:"Neuter. Also: die Milch (milk), der Kaffee (coffee), der Tee (tea).",example:"A: Wasser oder Milch?\nB: Kaffee, bitte!",exampleSrc:"A: Water or milk?\nB: Coffee, please!",funFact:"German water is almost always sparkling (mit Kohlensäure). Ask for 'stilles Wasser' if you want flat. This confuses every tourist."},
{type:"teach",trg:"der Saft",src:"the juice",note:"Masculine. Also: das Bier (beer), der Wein (wine).",example:"A: Saft für die Kinder?\nB: Und Wein für uns.",exampleSrc:"A: Juice for the kids?\nB: And wine for us.",funFact:"Germans can legally drink beer and wine at 16. Spirits at 18. Saft (juice) is for the youngsters."},
{type:"teach",trg:"das Getränk",src:"the drink / beverage",note:"Neuter. Also: die Flasche (bottle), das Glas (glass).",example:"A: Ein Getränk, bitte.\nB: Flasche oder Glas?",exampleSrc:"A: A drink, please.\nB: Bottle or glass?",funFact:"'Flasche' also means 'loser' in slang. Don't call someone a Flasche."},
{type:"teach",trg:"das Lebensmittel",src:"the food / groceries",note:"Neuter. Literally: means-of-life.",example:"A: Die Lebensmittel sind frisch.\nB: Ja, sehr gut.",exampleSrc:"A: The groceries are fresh.\nB: Yes, very good.",funFact:"Leben (life) + Mittel (means) = means of life. German compound poetry at its finest."},
{type:"mc",q:"What is 'der Apfel'?",opts:["bread","fish","apple","egg"],ans:"apple",hint:"A round red fruit from the produce section."},
{type:"mc",q:"Which is neuter (das)?",opts:["der Kuchen","die Banane","das Brot","die Milch"],ans:"das Brot",hint:"Baked goods often take das in German."},
{type:"match",pairs:[{trg:"der Fisch",src:"fish"},{trg:"die Kartoffel",src:"potato"},{trg:"das Hähnchen",src:"chicken"},{trg:"die Flasche",src:"bottle"},{trg:"das Gemüse",src:"vegetables"}]},
{type:"fb",s:"Ich trinke gern {1}.",a:["Kaffee"],opts:["Kaffee","Salat","Brot","Fleisch"],hint:"Which one is a drink, not food?",sSrc:"I like to drink coffee."},
{type:"mc",q:"What does 'Lebensmittel' literally mean?",opts:["means of life","food store","daily bread","fresh items"],ans:"means of life",hint:"Translate each part of this compound noun separately."},
{type:"match",pairs:[{trg:"das Ei",src:"egg"},{trg:"die Butter",src:"butter"},{trg:"der Reis",src:"rice"},{trg:"der Schinken",src:"ham"},{trg:"das Salz",src:"salt"}]},
{type:"mc",q:"'Die Tomaten _____ frisch.'",opts:["ist","sind","hat","haben"],ans:"sind",hint:"Tomaten is plural. Plural verb form needed."},
{type:"story",speaker:"verumius",mood:"hopeful",art:"de-rewe-basket-fruit",trg:"Ich lege die gelben Dinge in den Korb. Und die roten. Und... ich weiß nicht, was das ist, aber es riecht gut.",src:"I put the yellow things in the basket. And the red ones. And... I don't know what that is, but it smells good."}
]},

// ─── L3: Nummern, Farben, Gewichte ───
{id:"deu_r4l3",title:"Nummern, Farben, Gewichte",icon:"🔢",xp:15,board:true,steps:[
{type:"intro",title:"Nummern, Farben, Gewichte",desc:"Numbers beyond 20, all the colors, and how to weigh produce. The deli counter awaits: you MUST know your Gramm from your Kilo.",goals:["Count to 1,000+","Name all basic colors","Weights and measurements"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-rewe-bakery-counter",trg:"Die Bäckerei-Theke. Hinter dem Glas: Brötchen, Brezeln, Kuchen. Vor dem Glas: sechs Menschen. Sie warten. Verumius wartet auch. Zehn Minuten.",src:"The bakery counter. Behind the glass: rolls, pretzels, cake. In front of the glass: six people. They wait. Verumius waits too. Ten minutes."},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-rewe-bakery-number",trg:"Eine Frau hinter ihm sagt: 'Haben Sie eine Nummer?' Verumius sieht den roten Automaten an der Wand. NUMMER ZIEHEN. Er hat keine Nummer gezogen.",src:"A woman behind him says: 'Do you have a number?' Verumius sees the red machine on the wall. TAKE A NUMBER. He did not take a number."},
{type:"story",speaker:"verumius",mood:"embarrassed",art:"de-rewe-number-ticket",trg:"Nummer 47. Die Anzeige sagt: 38. Ich hatte keine Nummer. Jetzt habe ich eine. Aber neun Menschen sind vor mir.",src:"Number 47. The display says: 38. I had no number. Now I have one. But nine people are ahead of me."},
{type:"teach",trg:"dreißig / vierzig / fünfzig",src:"30 / 40 / 50",note:"Tens: add -zig to the root. dreißig is the exception (not dreizig).",example:"A: Dreißig Euro?\nB: Nein, vierzig!",exampleSrc:"A: Thirty euros?\nB: No, forty!",funFact:"German flips digit order: 43 = 'dreiundvierzig' (three-and-forty). Brain breaker for English speakers. Get used to it!"},
{type:"teach",trg:"sechzig / siebzig / achtzig / neunzig",src:"60 / 70 / 80 / 90",note:"Siebzig (not siebenzig). The 'en' gets eaten.",example:"A: Siebzig oder sechzig?\nB: Achtzig!",exampleSrc:"A: Seventy or sixty?\nB: Eighty!",funFact:"Siebzig drops the 'en': sieben to siebzig. Same thing happens with siebte (7th). German likes trimming."},
{type:"teach",trg:"hundert / tausend",src:"100 / 1,000",note:"'Ein' before them is optional: hundert = einhundert.",example:"A: Hundert Euro!\nB: Nein, tausend!",exampleSrc:"A: A hundred euros!\nB: No, a thousand!",funFact:"Both forms correct: hundert or einhundert, tausend or eintausend. Germans are flexible here."},
{type:"tip",title:"Compound Numbers Above 20",text:"German numbers above 20 are built units-first:\n\n21 = einundzwanzig (one and twenty)\n22 = zweiundzwanzig (two and twenty)\n35 = fünfunddreißig (five and thirty)\n47 = siebenundvierzig (seven and forty)\n\nPattern: units + und + tens.\nAll written as one word.",deepDive:{title:"Why does German say 'one-and-twenty' instead of 'twenty-one'?",text:"Old English used the same structure: 'one and twenty' appears in Shakespeare and older texts. Most Germanic languages historically put the smaller number first. English switched to the modern 'twenty-one' order but German kept the old pattern. Dutch also says 'eenentwintig.' Once you get the rhythm, it becomes automatic."}},
{type:"teach",trg:"die Farbe",src:"the color",note:"Feminine. Colors as adjectives are lowercase: rot, blau, grün.",example:"A: Welche Farbe?\nB: Rot!",exampleSrc:"A: Which color?\nB: Red!",funFact:"German color words don't capitalize unless they are nouns (das Rot). As adjectives: always lowercase."},
{type:"teach",trg:"rot / blau / grün / gelb",src:"red / blue / green / yellow",note:"Basic colors. Used as adjectives (no ending when predicative).",example:"A: Der Apfel ist rot.\nB: Die Banane ist gelb.",exampleSrc:"A: The apple is red.\nB: The banana is yellow.",funFact:"Rot, blau, grün, gelb: four primary colors every child learns first. 'Grün hinter den Ohren' (green behind the ears) = naive/inexperienced."},
{type:"teach",trg:"schwarz / weiß / braun / grau",src:"black / white / brown / grey",note:"More colors. Schwarz and weiß are common in compound nouns.",example:"A: Schwarz oder weiß?\nB: Grau!",exampleSrc:"A: Black or white?\nB: Grey!",funFact:"Schwarzbrot (black bread), Weißwurst (white sausage), Braunschweig (city name!). Colors build food compounds."},
{type:"teach",trg:"das Gramm / das Kilogramm",src:"gram / kilogram",note:"Both neuter. Stay singular with numbers: 500 Gramm, never Gramme.",example:"A: Zweihundert Gramm Schinken, bitte.\nB: Hier, genau zweihundert.",exampleSrc:"A: Two hundred grams of ham, please.\nB: Here, exactly two hundred.",funFact:"At the Fleischtheke (deli counter), you order by Gramm. '200 Gramm Schinken' is the magic phrase. Never say 'Gramme.'"},
{type:"teach",trg:"das Pfund",src:"the pound (500g in Germany!)",note:"Neuter. German Pfund = 500g, NOT 454g like English pound!",example:"A: Ein halbes Pfund Butter.\nB: Und ein Liter Milch?",exampleSrc:"A: Half a pound of butter.\nB: And a liter of milk?",funFact:"Pfund = 500g in Germany. Not 454g like the English pound. Metric country! 'Ein halbes Pfund' = 250g."},
{type:"teach",trg:"der Liter / der Meter",src:"liter / meter",note:"Both masculine. Germany went metric in 1872.",example:"A: Hundert Zentimeter sind ein Meter.\nB: Und tausend Meter sind ein Kilometer.",exampleSrc:"A: A hundred centimeters is one meter.\nB: And a thousand meters is one kilometer.",funFact:"Germany went metric in 1872. They think in meters like you think in feet. Zentimeter, Kilometer: all masculine."},
{type:"teach",trg:"die Nummer / die Größe / das Gewicht",src:"number / size / weight",note:"Three essential measurement words.",example:"A: Welche Nummer?\nB: Nummer fünfzig.",exampleSrc:"A: Which number?\nB: Number fifty.",funFact:"At the bakery counter you MUST take a number (Nummer ziehen). No number = no service. Germans queue by number, not by standing in line."},
{type:"teach",trg:"halb / das Viertel / zirka",src:"half / quarter / approximately",note:"'Halb' = half. 'Viertel' = quarter. 'Zirka' = about.",example:"A: Zirka eine Stunde.\nB: Ein Viertel ist genug.",exampleSrc:"A: About one hour.\nB: A quarter is enough.",funFact:"'Viertel nach drei' = quarter past three. 'Halb vier' = half TO four (= 3:30!). This German clock trap catches everyone."},
{type:"mc",q:"How do you say 73 in German?",opts:["siebzigdrei","siebendreißig","dreiundsiebzig","dreißigsieben"],ans:"dreiundsiebzig",hint:"German says the ones digit first, then 'und', then tens."},
{type:"mc",q:"'Zweihundertfünfundvierzig' = ?",opts:["254","452","245","542"],ans:"245",hint:"zweihundert=200, fünfundvierzig=45."},
{type:"fb",s:"Zweihundert {1} Schinken, bitte.",a:["Gramm"],opts:["Gramm","Liter","Meter","Grad"],hint:"Which unit measures weight for deli items?",sSrc:"Two hundred grams of ham, please."},
{type:"match",pairs:[{trg:"rot",src:"red"},{trg:"blau",src:"blue"},{trg:"gelb",src:"yellow"},{trg:"grün",src:"green"},{trg:"schwarz",src:"black"}]},
{type:"mc",q:"'Zirka ein Kilo' means:",opts:["about one kilogram","exactly one kilogram","half a kilogram","two kilograms"],ans:"about one kilogram",hint:"Zirka means approximately."},
{type:"fb",s:"Ein {1} Pfund Butter, bitte.",a:["halbes"],opts:["halbes","ganzes","großes","kleines"],hint:"You want 250g, which is half of a Pfund.",sSrc:"A half pound of butter, please."},
{type:"mc",q:"Which color means 'grey'?",opts:["grau","grün","braun","blau"],ans:"grau",hint:"It starts with 'gr' but is NOT green."},
{type:"match",pairs:[{trg:"die Nummer",src:"number"},{trg:"das Gewicht",src:"weight"},{trg:"die Größe",src:"size"},{trg:"das Viertel",src:"quarter"},{trg:"die Stunde",src:"hour"}]},
{type:"fb",s:"Das Brot kostet drei Euro fünfzig {1}.",a:["Cent"],opts:["Cent","Euro","Prozent","Gramm"],hint:"The small coin denomination after Euro.",sSrc:"The bread costs three euros fifty cents."},
{type:"story",speaker:"narrator",mood:"amused",art:"de-rewe-scale",trg:"Die Waage bei den Bananen. Verumius legt sie drauf. Ein Bildschirm mit hundert Bildern. Er drückt auf Brokkoli. Die Bananen kosten jetzt 0,49 Euro pro Kilo. Das ist falsch. Sehr falsch.",src:"The scale by the bananas. Verumius puts them on. A screen with a hundred pictures. He presses broccoli. The bananas now cost 0.49 euros per kilo. That is wrong. Very wrong."}
]},

// ─── L4: Akkusativ-Alarm ───
{id:"deu_r4l4",title:"Akkusativ-Alarm",icon:"⚡",xp:20,board:true,steps:[
{type:"intro",title:"Akkusativ-Alarm",desc:"The accusative case changes ONE article: der becomes den. That's it. One gender, one change. But it changes everything about how you shop.",goals:["Accusative case (den/einen)","Negative article kein","nicht vs kein distinction"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-rewe-aisle",trg:"Gang drei. Milch, Butter, Käse, Joghurt. Alles hat Artikel. Der Käse. Die Butter. Das Joghurt. Verumius denkt: Warum hat Käse ein Geschlecht?",src:"Aisle three. Milk, butter, cheese, yogurt. Everything has articles. Der Käse. Die Butter. Das Joghurt. Verumius thinks: Why does cheese have a gender?"},
{type:"teach",trg:"teuer",src:"expensive",note:"Adjective. Opposite: billig (cheap). Better word: günstig (good value).",example:"A: Das ist teuer!\nB: Nein, das ist günstig.",exampleSrc:"A: That is expensive!\nB: No, that is good value.",funFact:"'Günstig' does not mean cheap. It means good value. Germans make this distinction seriously. Billig = cheap (negative). Günstig = well-priced (positive)."},
{type:"teach",trg:"viel / wenig / mehr",src:"much / little / more",note:"Viel = much/many. Wenig = little/few. Mehr = more (comparative).",example:"A: Ich brauche mehr Milch.\nB: Wir haben nicht viel.",exampleSrc:"A: I need more milk.\nB: We don't have much.",funFact:"'Mehr' never declines. No endings, ever. 'Die meisten Leute' = most people. Meist is the superlative of viel."},
{type:"tip",title:"Accusative Case (der Akkusativ)",text:"The direct object case. What changes?\n\nder becomes den (masculine ONLY)\nein becomes einen (masculine ONLY)\ndie / das / eine / ein(neut) = NO CHANGE\n\nNominative: Der Apfel ist rot.\nAccusative: Ich kaufe den Apfel.\n\nOnly masculine changes. Everything else stays the same.\nThis is the easiest German case.",deepDive:{title:"Why only masculine changes?",text:"In Old High German, all three genders had distinct accusative forms. Over centuries, the feminine and neuter accusative forms merged with the nominative. Only the masculine kept its distinct accusative: the -en ending (den, einen).\n\nThis is actually helpful: you only need to learn ONE change. If the noun is masculine, add -en to the article. If not, nothing changes."}},
{type:"teach",trg:"den / einen",src:"the / a (masculine accusative)",note:"Masculine accusative: der to den, ein to einen.",example:"A: Ich kaufe den Apfel.\nB: Und ich nehme einen Kuchen.",exampleSrc:"A: I am buying the apple.\nB: And I am taking a cake.",funFact:"Only ONE gender changes in accusative. Masculine gets an extra -en. Die and das? Lazy. No change."},
{type:"mc",q:"'Ich kaufe ___ Fisch.'",opts:["der","dem","des","den"],ans:"den",hint:"Fisch is masculine. Direct object = accusative case. What form?"},
{type:"fb",s:"Ich brauche {1} Apfel.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Apfel is masculine. In accusative, ein becomes...",sSrc:"I need an apple."},
{type:"mc",q:"'Ich esse ___ Banane.'",opts:["die","den","dem","der"],ans:"die",hint:"Banane is feminine. Feminine does NOT change in accusative."},
{type:"fb",s:"Er kauft {1} Brot.",a:["das"],opts:["das","den","der","die"],hint:"Brot is neuter. Neuter stays the same in accusative.",sSrc:"He buys the bread."},
{type:"tip",title:"kein: The Negative Article",text:"kein = 'not a' / 'no.' Declines like ein:\n\nNom: kein Apfel, keine Banane, kein Brot\nAcc: keinen Apfel, keine Banane, kein Brot\n\nMasculine adds -en in accusative.\nJust like ein becomes einen."},
{type:"teach",trg:"kein / keinen / keine",src:"no / not a (negative article)",note:"Follows ein-pattern. keinen for masculine accusative.",example:"A: Hast du einen Apfel?\nB: Nein, ich habe keinen Apfel.",exampleSrc:"A: Do you have an apple?\nB: No, I don't have an apple.",funFact:"Kein is ein's evil twin. Same endings, opposite meaning. Master ein-endings, and kein is free."},
{type:"mc",q:"'Ich habe ___ Geld.'",opts:["keinen","kein","keine","keiner"],ans:"kein",hint:"Geld is neuter. You are negating a noun. Which negator for neuter nouns?"},
{type:"fb",s:"Wir haben {1} Milch.",a:["keine"],opts:["keine","kein","keinen","keiner"],hint:"Milch is feminine. What form does kein take with feminine nouns?",sSrc:"We have no milk."},
{type:"mc",q:"'Er kauft ___ Schinken.' (none)",opts:["kein","keinen","keine","keinem"],ans:"keinen",hint:"Schinken is masculine. Accusative masculine kein gets -en."},
{type:"tip",title:"nicht vs kein",text:"When to use which?\n\nKEIN replaces ein/eine before nouns:\n'Ich habe ein Auto' to 'Ich habe kein Auto'\n\nNICHT negates verbs, adjectives, adverbs:\n'Ich kaufe nicht' / 'Das ist nicht teuer'\n\nNICHT goes before what it negates.\nKEIN goes before the noun."},
{type:"mc",q:"'Das Brot ist ___ frisch.'",opts:["kein","keinen","nicht","keine"],ans:"nicht",hint:"Is the negated word a noun or an adjective/verb? The negator depends on this."},
{type:"fb",s:"Ich kaufe {1} Fleisch.",a:["kein"],opts:["kein","nicht","keinen","keine"],hint:"Negating a neuter noun. Which negative article?",sSrc:"I am buying no meat."},
{type:"mc",q:"'Ich trinke ___ .'",opts:["nicht","kein","keinen","keine"],ans:"nicht",hint:"Nothing being negated is a noun. What negator works for verbs?"},
{type:"drag_fill",s:"Ich habe {1} Geld und kaufe {2} ein.",blanks:{"1":"kein","2":"nicht"},pool:["kein","nicht","keinen","keine"],hint:"First blank negates a neuter noun. Second blank negates the verb itself, not a noun.",sSrc:"I have no money and am not shopping."},
{type:"mc",q:"'Wir brauchen ___ Eier.'",opts:["nicht","kein","keine","keinen"],ans:"keine",hint:"Eier is plural. What ending does the noun-negator need for plural?"},
{type:"fb",s:"Die Tomaten sind {1} billig.",a:["nicht"],opts:["nicht","keine","kein","keinen"],hint:"Negating the adjective 'billig', not a noun.",sSrc:"The tomatoes are not cheap."},
{type:"drag_fill",s:"Ich kaufe {1} Fisch. Der Fisch ist {2} günstig.",blanks:{"1":"keinen","2":"nicht"},pool:["keinen","nicht","kein","keine"],hint:"First: masculine noun accusative. Second: negating adjective.",sSrc:"I am buying no fish. The fish is not affordable."},
{type:"mc",q:"'Er hat ___ Kreditkarte.'",opts:["nicht","keine","kein","keinen"],ans:"keine",hint:"Kreditkarte is feminine. What ending does the noun-negator need?"},
{type:"story",speaker:"verumius",mood:"determined",art:"de-rewe-list",trg:"Ich brauche den Käse. Nicht der Käse. DEN Käse. Akkusativ. Yilmaz hat das gesagt. Ich kaufe den Käse. Ich kaufe die Milch. Ich kaufe... das... Joghurt?",src:"I need den Käse. Not der Käse. DEN Käse. Accusative. Yilmaz said that. I buy den Käse. I buy die Milch. I buy... das... Joghurt?"}
]},

// ─── L5: Für, Ohne, Gegen ───
{id:"deu_r4l5",title:"Für, Ohne, Gegen",icon:"🎯",xp:20,board:true,steps:[
{type:"intro",title:"Für, Ohne, Gegen",desc:"Five prepositions that ALWAYS take accusative. Plus demonstrative articles and the imperative. Grammar-heavy, but you already know the accusative.",goals:["5 accusative prepositions (DOGFU)","Demonstrative articles: dieser/jeder","Basic imperative commands"]},
{type:"story",speaker:"verumius",mood:"lost",art:"de-rewe-lost-aisle",trg:"Ich suche das Mehl. Ohne Plan, ohne Karte. Gegen die Logik: das Mehl ist nicht bei den Backwaren. Es ist bei den Konserven. Warum?",src:"I am looking for the flour. Without a plan, without a map. Against all logic: the flour is not with the baked goods. It is with the canned goods. Why?"},
{type:"teach",trg:"ohne",src:"without",note:"Preposition. Always takes accusative.",example:"A: Kaffee ohne Milch?\nB: Ja, ohne Milch und ohne Zucker.",exampleSrc:"A: Coffee without milk?\nB: Yes, without milk and without sugar.",funFact:"'Ohne mich!' = Count me out! Always takes accusative. Ohne einen Euro = without a euro."},
{type:"teach",trg:"bitten",src:"to ask / to request",note:"Irregular: ich bitte, du bittest. 'Bitten um' = ask for.",example:"A: Ich bitte um Hilfe.\nB: Natürlich!",exampleSrc:"A: I am asking for help.\nB: Of course!",funFact:"'Bitten um' always takes accusative. 'Bitte' (please) comes from this verb. The most polite word in German has aggressive grammar."},
{type:"teach",trg:"geben",src:"to give",note:"Irregular: ich gebe, du gibst, er gibt.",example:"A: Gibst du mir den Apfel?\nB: Ja, ich gebe dir den Apfel.",exampleSrc:"A: Are you giving me the apple?\nB: Yes, I am giving you the apple.",funFact:"'Geben' takes dative for the person and accusative for the thing. For now, focus on the accusative object: den Apfel, die Milch, das Brot."},
{type:"tip",title:"DOGFU: 5 Accusative Prepositions",text:"Five prepositions ALWAYS take accusative:\n\nDurch (through): durch den Laden\nOhne (without): ohne einen Euro\nGegen (against): gegen den Preis\nFür (for): für die Familie\nUm (around): um die Ecke\n\nMnemonic: DOGFU.\nOnly masculine changes: den/einen."},
{type:"mc",q:"'Das Geschenk ist für ___ Kundin.'",opts:["den","die","dem","der"],ans:"die",hint:"Kundin is feminine. Feminine doesn't change in accusative."},
{type:"fb",s:"Ich gehe durch {1} Laden.",a:["den"],opts:["den","der","dem","das"],hint:"'Durch' always demands the same case. Apply it to a masculine noun.",sSrc:"I walk through the store."},
{type:"mc",q:"Fill in: 'Kaffee ohne ___.'",opts:["die Milch","der Milch","den Milch","Milch"],ans:"Milch",hint:"After ohne, no article needed when speaking generally about a substance."},
{type:"fb",s:"Das ist für {1} Verkäufer.",a:["den"],opts:["den","der","dem","des"],hint:"Verkäufer is masculine. Für always takes accusative.",sSrc:"That is for the salesperson."},
{type:"tip",title:"Demonstrativartikel",text:"dieser/jeder/welcher decline like der/die/das:\n\nMasc nom: dieser, jeder, welcher\nMasc acc: diesen, jeden, welchen\nFem: diese, jede, welche (no change nom/acc)\nNeut: dieses, jedes, welches (no change nom/acc)\nPlural: diese, alle, welche",deepDive:{title:"The dieser pattern",text:"Dieser (this/these) mirrors der/die/das endings exactly. The trick: replace der/die/das with dies- and keep the same ending.\n\nder Mantel becomes dieser Mantel\ndie Hose becomes diese Hose\ndas Hemd becomes dieses Hemd\n\nIn accusative, only masculine changes: dieser becomes diesen, just like der becomes den.\n\nThe same pattern applies to jeder (every) and welcher (which). Learn one set of endings, and you know all three."}},
{type:"teach",trg:"was für ein / was für eine",src:"what kind of (a)",note:"'Was für' + ein-word. The ein-part declines normally.",example:"A: Was für einen Kuchen möchtest du?\nB: Einen Schokoladenkuchen!",exampleSrc:"A: What kind of cake would you like?\nB: A chocolate cake!",funFact:"'Was für ein' = what kind of. Masculine acc: was für einen. Feminine: was für eine. Neuter: was für ein."},
{type:"mc",q:"'___ Apfel möchtest du?'",opts:["Welcher","Welches","Welche","Welchen"],ans:"Welchen",hint:"Apfel is masculine, direct object (accusative). Welch- + masc acc = -en."},
{type:"fb",s:"Ich kaufe {1} Flasche.",a:["diese"],opts:["diese","diesen","dieser","dieses"],hint:"Flasche is feminine. It is the direct object here. Check the dieser-word endings chart for this combination.",sSrc:"I am buying this bottle."},
{type:"mc",q:"'___ Brot schmeckt gut?'",opts:["Welcher","Welches","Welchen","Welche"],ans:"Welches",hint:"Brot is neuter, nominative. Think about the dieser-word endings chart."},
{type:"fb",s:"Ich nehme {1} Kuchen.",a:["diesen"],opts:["diesen","dieser","dieses","diese"],hint:"Kuchen is masculine, direct object (accusative). Masculine accusative ending?",sSrc:"I will take this cake."},
{type:"tip",title:"Imperative (Commands)",text:"Giving commands in German:\n\ndu-form: verb stem: Kauf! Nimm! Gib!\nihr-form: same as ihr-present: Kauft! Nehmt!\nSie-form: infinitive + Sie: Kaufen Sie! Nehmen Sie!\n\nSeparable verbs split: Kauf ein! Kaufen Sie ein!\nSie-form is the polite one. Always use it with strangers."},
{type:"mc",q:"'Buy!' (polite) in German:",opts:["Kauf!","Kaufen Sie!","Kauft!","Kaufe!"],ans:"Kaufen Sie!",hint:"Polite imperative uses the Sie-form: infinitive + Sie."},
{type:"fb",s:"{1} den Apfel!",a:["Nimm"],opts:["Nimm","Nehmen","Nimmst","Nimmt"],hint:"Informal du-command. What is the imperative stem of nehmen?",sSrc:"Take the apple!"},
{type:"mc",q:"'_____ bitte hier!' (polite: pay here)",opts:["Zahlen Sie","Zahl","Zahlt","Zahlst du"],ans:"Zahlen Sie",hint:"Polite command = infinitive + Sie."},
{type:"drag_fill",s:"{1} Sie {2} den Laden!",blanks:{"1":"Gehen","2":"durch"},pool:["Gehen","durch","Geht","für"],hint:"Polite imperative of the verb meaning 'to walk' + a directional prefix.",sSrc:"Go through the store!"},
{type:"mc",q:"'Für welch___ Kundin ist das?'",opts:["welchen","welcher","welches","welche"],ans:"welche",hint:"Kundin is feminine. Accusative feminine = no change."},
{type:"fb",s:"Ohne {1} Euro geht nichts.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Euro is masculine. Ohne requires accusative. How does ein change for masc acc?",sSrc:"Without a euro nothing works."},
{type:"drag_fill",s:"{1} Sie {2} Kreditkarte für {3} Einkauf!",blanks:{"1":"Nehmen","2":"die","3":"den"},pool:["Nehmen","die","den","Nimm","der","das"],hint:"Polite imperative. Kreditkarte is fem (die). Einkauf is masc acc (den).",sSrc:"Take the credit card for the purchase!"},
{type:"mc",q:"'Was für ___ Brot möchtest du?'",opts:["einen","eine","ein","einer"],ans:"ein",hint:"Brot is neuter. Accusative neuter ein = no change."},
{type:"story",speaker:"narrator",mood:"amused",art:"de-rewe-employee",trg:"Ein Mitarbeiter sortiert Regale. Verumius fragt: 'Das Mehl?' Der Mann zeigt nach links. Dann nach rechts. Dann sagt er: 'Gang sieben. Glaube ich.'",src:"An employee sorts shelves. Verumius asks: 'The flour?' The man points left. Then right. Then says: 'Aisle seven. I think.'"},
{type:"story",speaker:"verumius",mood:"relieved",art:"de-rewe-flour-found",trg:"Gang sieben. Da ist es. Mehl. Für Hildi. Sie hat gesagt: 'Ohne Mehl kein Kuchen.' Das verstehe ich auch ohne Wörterbuch.",src:"Aisle seven. There it is. Flour. For Hildi. She said: 'Without flour, no cake.' I understand that even without a dictionary."}
]},

// ─── L6: Nummer Ziehen! ───
{id:"deu_r4l6",title:"Nummer Ziehen!",icon:"🎫",xp:15,board:true,steps:[
{type:"intro",title:"Nummer Ziehen!",desc:"The bakery counter. You MUST take a number. The deli weighs in Gramm. And you can pay bar or mit Karte. Maybe.",goals:["bekommen vs kriegen","Payment vocabulary","Quantities in practice"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-rewe-bakery-wait",trg:"Zurück an der Bäckerei-Theke. Die Anzeige sagt: 45. Verumius hat Nummer 47. Sein Herz schlägt schneller. Noch zwei. Eine Frau kauft drei Sorten Brot. Langsam.",src:"Back at the bakery counter. The display says: 45. Verumius has number 47. His heart beats faster. Two more. A woman buys three types of bread. Slowly."},
{type:"story",speaker:"narrator",mood:"excited",art:"de-rewe-bakery-turn",trg:"47! Die Verkäuferin schaut Verumius an. 'Bitte?' Er zeigt auf ein Brötchen. 'Zwei, bitte.' Sie nickt. Es funktioniert. Sprache funktioniert!",src:"47! The saleswoman looks at Verumius. 'Yes?' He points at a roll. 'Two, please.' She nods. It works. Language works!"},
{type:"teach",trg:"bekommen",src:"to get / to receive",note:"FALSE FRIEND: does NOT mean 'to become'!",example:"A: Was bekommen Sie?\nB: Ich bekomme zwei Brötchen.",exampleSrc:"A: What would you like? (lit: What do you get?)\nB: I'll have two bread rolls.",funFact:"'Was bekommen Sie?' is how EVERY German shop assistant asks what you want. Bekommen does NOT mean 'become.' That trap catches every English speaker. 'Werden' = to become."},
{type:"teach",trg:"kriegen",src:"to get (casual synonym of bekommen)",note:"Casual. 'Ich kriege einen Kaffee.' Same meaning as bekommen.",example:"A: Was kriegst du?\nB: Ich kriege ein Brötchen.",exampleSrc:"A: What are you getting?\nB: I'm getting a bread roll.",funFact:"'Kriegen' also historically means 'to wage war' (der Krieg = war). But in everyday speech it just means 'to get.' Context is everything."},
{type:"teach",trg:"anbieten",src:"to offer",note:"Separable: wir bieten... an. 'Das Angebot' comes from this verb.",example:"A: Was bieten Sie an?\nB: Wir bieten frisches Brot an.",exampleSrc:"A: What do you offer?\nB: We offer fresh bread.",funFact:"Separable: an|bieten. 'Das Angebot' (the offer) is the noun form. Compound magic: verb to noun in one step."},
{type:"teach",trg:"bar",src:"cash (adjective/adverb)",note:"'Bar zahlen' = pay cash. Noun 'die Bar' = a pub/bar.",example:"A: Zahlen Sie bar?\nB: Ja, bar bitte.",exampleSrc:"A: Are you paying cash?\nB: Yes, cash please.",funFact:"'Bar' as payment = cash. 'Die Bar' as a place = pub. Same word, totally different meaning and gender!"},
{type:"teach",trg:"leicht / schwer",src:"light / heavy (also: easy / difficult)",note:"Both have double meanings: physical weight AND difficulty.",example:"A: Ist die Tasche schwer?\nB: Nein, sie ist leicht.",exampleSrc:"A: Is the bag heavy?\nB: No, it is light.",funFact:"'Schwer' also means 'difficult.' 'Leicht' also means 'easy.' 'Das war schwer!' could mean heavy OR hard. Context saves you."},
{type:"teach",trg:"überweisen",src:"to transfer (money)",note:"Inseparable: ich überweise. Also: die Bank, das Konto.",example:"A: Ich überweise das Geld.\nB: Auf welches Konto?",exampleSrc:"A: I am transferring the money.\nB: To which account?",funFact:"Germans LOVE bank transfers (Überweisungen). Many bills are paid this way, not by card. The Überweisung is a German institution."},
{type:"tip",title:"At the Bakery Counter",text:"Verumius stands at the Bäckerei counter.\nNo number. 'Wer ist dran?' calls the baker.\nThree people wave their numbers.\nVerumius stares.\n\nThe annoyed customer behind him sighs:\n'Nummer ziehen!'\nPull a number!\n\nLesson learned: always take a number at German counters."},
{type:"mc",q:"'Was bekommen Sie?' means:",opts:["What are you becoming?","What do you know?","Where are you going?","What would you like?"],ans:"What would you like?",hint:"Bekommen = to get/receive, NOT to become!"},
{type:"fb",s:"Wir {1} frischen Kuchen an.",a:["bieten"],opts:["bieten","bietet","anbieten","bitten"],hint:"Separable verb: the 'an' is at the end. The verb stem goes in the blank.",sSrc:"We offer fresh cake."},
{type:"mc",q:"'Zahlen Sie ___?'",opts:["teuer","bar","billig","schwer"],ans:"bar",hint:"The cashier asks about your payment method. Physical money = ?"},
{type:"fb",s:"Die Tasche ist {1}. Sie hat viel Obst.",a:["schwer"],opts:["schwer","leicht","teuer","billig"],hint:"A bag full of fruit is not light.",sSrc:"The bag is heavy. It has a lot of fruit."},
{type:"drag_fill",s:"Ich {1} zweihundert Gramm Schinken und {2} Brötchen.",blanks:{"1":"bekomme","2":"drei"},pool:["bekomme","drei","kriege","ohne"],hint:"'I get' at the deli counter. Plus a number of bread rolls.",sSrc:"I get two hundred grams of ham and three bread rolls."},
{type:"mc",q:"'Ich habe ___ Bargeld. Kann ich mit Karte zahlen?'",opts:["nicht","keinen","kein","keine"],ans:"kein",hint:"Bargeld is neuter. Negating a noun. Does the negator change for neuter?"},
{type:"fb",s:"Nehmen {1} diesen Kuchen!",a:["Sie"],opts:["Sie","du","ihr","er"],hint:"Polite imperative: verb + ?",sSrc:"Take this cake!"},
{type:"mc",q:"'Dieser Fisch ist ___ frisch.'",opts:["kein","keinen","nicht","keine"],ans:"nicht",hint:"You are negating an adjective, not a noun. Which negator goes with adjectives?"},
{type:"drag_fill",s:"Kaufen Sie {1} Gramm Schinken {2} den Preis von drei Euro.",blanks:{"1":"zweihundert","2":"für"},pool:["zweihundert","für","durch","dreihundert"],hint:"200g of ham at a certain price. Which DOGFU preposition means 'for the purpose of'?",sSrc:"Buy two hundred grams of ham for the price of three euros."},
{type:"match",pairs:[{trg:"bekommen",src:"to get/receive"},{trg:"anbieten",src:"to offer"},{trg:"überweisen",src:"to transfer money"},{trg:"bar",src:"cash"},{trg:"schwer",src:"heavy/difficult"}]},
{type:"mc",q:"'Für ___ Konto ist die Überweisung?'",opts:["welcher","welches","welchen","welche"],ans:"welches",hint:"Konto is neuter. Für needs accusative. What ending for welch- with neuter acc?"},
{type:"story",speaker:"verumius",mood:"proud",art:"de-rewe-bread-bag",trg:"Zwei Brötchen in einer Papiertüte. Warm. Das ist mein erster Erfolg in einem deutschen Supermarkt. Klein, aber echt.",src:"Two bread rolls in a paper bag. Warm. This is my first success in a German supermarket. Small, but real."}
]},

// ─── L7: Speed Checkout Terror ───
{id:"deu_r4l7",title:"Speed Checkout Terror",icon:"⚡",xp:20,board:true,steps:[
{type:"intro",title:"Speed Checkout Terror",desc:"The moment of truth. Items fly across the scanner. The cashier doesn't pause. The next customer is already loading. ALL grammar from this unit in action.",goals:["Test all 6 grammar constructs","Multi-construct combinations","Survive the Kasse"]},
{type:"story",speaker:"narrator",mood:"dramatic",art:"de-rewe-checkout-belt",trg:"Die Kasse. Das Fließband. Die Kassiererin. Sie nimmt das erste Produkt. Piep. Das zweite. Piep. Das dritte, vierte, fünfte. PiepPiepPiep. Schneller als Verumius denken kann.",src:"The checkout. The conveyor belt. The cashier. She picks up the first item. Beep. The second. Beep. Third, fourth, fifth. BeepBeepBeep. Faster than Verumius can think."},
{type:"story",speaker:"verumius",mood:"panicked",art:"de-rewe-checkout-pile",trg:"Die Produkte kommen schneller als ich packen kann. Milch, Bananen, Käse, alles rutscht. Der Mann hinter mir legt schon seine Sachen auf das Band. SEINE Sachen. Neben MEINEN Sachen.",src:"The products come faster than I can pack. Milk, bananas, cheese, everything slides. The man behind me is already placing his things on the belt. HIS things. Next to MY things."},
{type:"story",speaker:"narrator",mood:"tense",art:"de-rewe-checkout-question",trg:"'Brauchen Sie eine Tüte?' Verumius versteht das Wort nicht. Tüte? Was ist eine Tüte? Er sagt: 'Ja?' Es kostet zwanzig Cent. Für eine Plastiktüte.",src:"'Do you need a bag?' Verumius does not understand the word. Tüte? What is a Tüte? He says: 'Yes?' It costs twenty cents. For a plastic bag."},
{type:"tip",title:"The Speed Checkout",text:"The conveyor belt moves. Verumius places his items:\nden Fisch, die Bananen, das Brot, keine Tüte.\nThe cashier scans without looking up.\n'Dreiundvierzig Euro achtundsiebzig.'\nVerumius fumbles for his Kreditkarte.\n'Nur bar!' says the cashier.\nPanic."},
{type:"mc",q:"'Verumius kauft ___ Fisch.'",opts:["der","dem","den","des"],ans:"den",hint:"Fisch is masculine. Direct object = accusative = den."},
{type:"fb",s:"Das Hähnchen kostet {1} Euro fünfzig.",a:["neun"],opts:["neun","neunzig","neunhundert","neuntausend"],hint:"A chicken costs less than ten euros.",sSrc:"The chicken costs nine euros fifty."},
{type:"mc",q:"'Er hat ___ Tüte.'",opts:["nicht","kein","keine","keinen"],ans:"keine",hint:"Tüte is feminine. What ending does the noun-negator need for feminine?"},
{type:"drag_fill",s:"Ich kaufe {1} Liter Milch und {2} Gramm Butter {3} die Familie.",blanks:{"1":"einen","2":"zweihundert","3":"für"},pool:["einen","zweihundert","für","ein","dreihundert","ohne"],hint:"Liter is masculine in the accusative. The quantity is 200g. Third blank: which DOGFU preposition means 'for'?",sSrc:"I am buying one liter of milk and two hundred grams of butter for the family."},
{type:"mc",q:"'___ Brot möchten Sie?'",opts:["Welcher","Welches","Welchen","Welche"],ans:"Welches",hint:"Brot is neuter, accusative. Check the demonstrative endings for neuter."},
{type:"fb",s:"Geben Sie mir {1} Rechnung!",a:["die"],opts:["die","den","der","das"],hint:"Rechnung is feminine. Acc feminine = no change from nom.",sSrc:"Please give me the bill!"},
{type:"mc",q:"'Der Wein ist nicht ___. Nur drei Euro.'",opts:["billig","günstig","schwer","teuer"],ans:"teuer",hint:"At 3 euros, the wine is NOT expensive."},
{type:"drag_fill",s:"Zahlen Sie {1} oder mit {2}?",blanks:{"1":"bar","2":"Karte"},pool:["bar","Karte","Geld","Bank"],hint:"Cash or with card? Two payment methods.",sSrc:"Are you paying cash or with card?"},
{type:"mc",q:"'Ich gehe ___ den Supermarkt.'",opts:["durch","für","mit","bei"],ans:"durch",hint:"Movement THROUGH something. First letter of DOGFU."},
{type:"fb",s:"Ohne {1} Euro bekomme ich keinen Einkaufswagen.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Ohne requires a specific case. Think about what happens to the article.",sSrc:"Without a euro I cannot get a shopping cart."},
{type:"mc",q:"'Die Tomaten kosten einen Euro ___ Kilo.'",opts:["das","den","für","pro"],ans:"pro",hint:"Per kilogram. 'Pro Kilo' means per kilo in German."},
{type:"drag_fill",s:"{1} Sie {2} Kuchen! Er ist heute im Angebot.",blanks:{"1":"Nehmen","2":"diesen"},pool:["Nehmen","diesen","Nimm","dieser"],hint:"Polite imperative. Kuchen is masculine. What form does the demonstrative take in accusative?",sSrc:"Take this cake! It is on offer today."},
{type:"fb",s:"Was für {1} Gemüse kaufst du?",a:["ein"],opts:["ein","einen","eine","einer"],hint:"Was für requires a specific article form. Think about the noun's gender.",sSrc:"What kind of vegetables are you buying?"},
{type:"mc",q:"Dreihundertfünfundsechzig = ?",opts:["365","356","563","653"],ans:"365",hint:"dreihundert=300, fünfundsechzig=65."},
{type:"match",pairs:[{trg:"teuer",src:"expensive"},{trg:"günstig",src:"good value"},{trg:"schwer",src:"heavy"},{trg:"leicht",src:"light/easy"},{trg:"billig",src:"cheap"}]},
{type:"drag_fill",s:"Ich habe {1} Bargeld und {2} Kreditkarte. Ich kann {3} bezahlen.",blanks:{"1":"kein","2":"keine","3":"nicht"},pool:["kein","keine","nicht","keinen"],hint:"First two blanks negate nouns (different genders). Third blank negates the verb, not a noun.",sSrc:"I have no cash and no credit card. I cannot pay at all."},
{type:"mc",q:"'Jed___ Kunde muss eine Nummer ziehen.'",opts:["jeden","jedes","jede","jeder"],ans:"jeder",hint:"Kunde is masculine. Nominative case. What form does jed- take?"},
{type:"fb",s:"Das Obst ist {1} als das Fleisch.",a:["leichter"],opts:["leichter","schwerer","teurer","billiger"],hint:"Fruit weighs less than meat. Comparative of leicht.",sSrc:"The fruit is lighter than the meat."},
{type:"mc",q:"'___ kaufen Sie ein?'",opts:["Was","Wer","Wo","Wann"],ans:"Was",hint:"Asking about WHAT you are shopping for."},
{type:"fb",s:"Der Preis {1} diesen Fisch ist sieben Euro.",a:["für"],opts:["für","ohne","gegen","durch"],hint:"The price FOR this fish. Which accusative preposition?",sSrc:"The price for this fish is seven euros."},
{type:"story",speaker:"narrator",mood:"relieved",art:"de-rewe-exit",trg:"Verumius steht vor REWE. Zwei volle Tüten. Rote Hände. Schweiß auf der Stirn. Er hat überlebt. Gerade so.",src:"Verumius stands outside REWE. Two full bags. Red hands. Sweat on his forehead. He survived. Barely."}
]},

// ─── L8: Küchenparade ───
{id:"deu_r4l8",title:"Küchenparade",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"Küchenparade",desc:"Verumius made it home. Bags borrowed, groceries secured. Time to review everything from the supermarket adventure. All 6 grammar constructs in multi-construct combinations.",goals:["Comprehensive Unit 4 review","Multi-construct quiz steps","Celebrate surviving German shopping"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-verumius-kitchen-groceries",trg:"Die Küche. Verumius legt alles auf den Tisch. Käse, Milch, Bananen (mit Brokkoli-Preis), Brötchen, Mehl. Mehr als er braucht. Weniger als er wollte.",src:"The kitchen. Verumius puts everything on the table. Cheese, milk, bananas (with broccoli price), rolls, flour. More than he needs. Less than he wanted."},
{type:"story",speaker:"verumius",mood:"proud",art:"de-verumius-phone-photo",trg:"Ich mache ein Foto und schicke es an Yilmaz. 'Mein erster Einkauf!' Sie antwortet sofort.",src:"I take a photo and send it to Yilmaz. 'My first shopping trip!' She replies immediately."},
{type:"story",speaker:"yilmaz",mood:"amused",art:"de-yilmaz-text",trg:"Sehr gut! Aber... wo ist das Brot? Und der Reis? Und die Eier? Hildi wird fragen.",src:"Very good! But... where is the bread? And the rice? And the eggs? Hildi will ask."},
{type:"tip",title:"Victory in the Kitchen",text:"Verumius stands in his kitchen. Results:\n\nNo bags (keine Tüte) = borrowed from a kind Kundin\nPfandautomat rejected his foreign bottle\nForgot to weigh his tomatoes\n\nBut: amazing bread, perfect Schinken, fresh Obst, and cheap Wein.\nVerumius: 1. German supermarket: 0."},
{type:"mc",q:"'Ich kaufe ___ Apfel und ___ Banane.'",opts:["ein ... eine","einen ... einen","einen ... eine","eine ... einen"],ans:"einen ... eine",hint:"One masculine direct object, one feminine direct object. How does ein change for each?"},
{type:"fb",s:"Zweihundert {1} Schinken, bitte.",a:["Gramm"],opts:["Gramm","Liter","Euro","Kilo"],hint:"Deli meat is weighed in this small unit.",sSrc:"Two hundred grams of ham, please."},
{type:"drag_fill",s:"Ich gehe {1} den Supermarkt und kaufe Obst {2} die Familie, aber {3} Fleisch.",blanks:{"1":"durch","2":"für","3":"ohne"},pool:["durch","für","ohne","gegen","um"],hint:"Through the store, fruit FOR the family, but WITHOUT meat.",sSrc:"I go through the supermarket and buy fruit for the family, but without meat."},
{type:"mc",q:"'Welch___ Brot nehmen Sie?'",opts:["Welcher","Welchen","Welche","Welches"],ans:"Welches",hint:"Brot is neuter. What form does welcher take for neuter accusative?"},
{type:"match",pairs:[{trg:"bezahlen",src:"to pay"},{trg:"überweisen",src:"to transfer"},{trg:"anbieten",src:"to offer"},{trg:"bekommen",src:"to receive"},{trg:"einkaufen",src:"to shop"}]},
{type:"fb",s:"Die Milch kostet ein Euro {1} Cent.",a:["fünfundsiebzig"],opts:["fünfundsiebzig","siebzigfünf","fünfsiebzig","siebenfünfzig"],hint:"German numbers: ones digit first, then und, then tens. Five-and-seventy.",sSrc:"The milk costs one euro seventy-five cents."},
{type:"drag_fill",s:"{1} Sie {2} Fisch! Er ist heute {3}.",blanks:{"1":"Kaufen","2":"den","3":"günstig"},pool:["Kaufen","den","günstig","Kauf","der","teuer"],hint:"Polite imperative + masculine accusative + good value.",sSrc:"Buy the fish! It is affordable today."},
{type:"mc",q:"'Er hat ___ Geld und ___ Kreditkarte.'",opts:["nicht ... nicht","kein ... keine","keinen ... keine","kein ... nicht"],ans:"kein ... keine",hint:"Two nouns: one neuter, one feminine. The noun-negator changes with gender."},
{type:"fb",s:"Jed{1} Kundin muss eine Nummer ziehen.",a:["e"],opts:["e","er","es","en"],hint:"Kundin is feminine. Jeder declines like der. Feminine nom = jede.",sSrc:"Every customer must take a number."},
{type:"mc",q:"'Was für ___ Wein möchten Sie?'",opts:["einen","ein","eine","einer"],ans:"einen",hint:"Wein is masculine and a direct object. How does ein change in accusative?"},
{type:"drag_fill",s:"Das Hähnchen kostet {1} Euro {2} und die Kartoffeln kosten {3} Euro {4}.",blanks:{"1":"acht","2":"neunzig","3":"zwei","4":"fünfzig"},pool:["acht","neunzig","zwei","fünfzig","neun","achtzig"],hint:"Chicken: 8 Euro 90. Potatoes: 2 Euro 50.",sSrc:"The chicken costs eight euros ninety and the potatoes cost two euros fifty."},
{type:"mc",q:"'Die rote Tasche ist ___. Die blaue ist günstig.'",opts:["billig","leicht","schwer","teuer"],ans:"teuer",hint:"Contrast with günstig. The red bag costs a lot."},
{type:"fb",s:"Ich brauche {1} Kilo Kartoffeln.",a:["ein"],opts:["ein","einen","eine","einer"],hint:"Kilo is neuter. Accusative neuter = no change.",sSrc:"I need one kilo of potatoes."},
{type:"mc",q:"'Nimm ___ Brötchen!' (informal)",opts:["den","das","der","die"],ans:"das",hint:"Brötchen is neuter. Du-imperative + neuter acc = das."},
{type:"drag_fill",s:"Verumius hat {1} Tüte und {2} Bargeld. Aber er hat {3} Obst!",blanks:{"1":"keine","2":"kein","3":"frisches"},pool:["keine","kein","frisches","keinen","keines","nicht"],hint:"First blank negates a feminine noun. Second blank negates a neuter noun. Third blank is an adjective, not a negator.",sSrc:"Verumius has no bag and no cash. But he has fresh fruit!"},
{type:"match",pairs:[{trg:"rot",src:"red"},{trg:"weiß",src:"white"},{trg:"grau",src:"grey"},{trg:"braun",src:"brown"},{trg:"gelb",src:"yellow"}]},
{type:"mc",q:"'Ohne ___ geht man nicht in den Supermarkt.'",opts:["einen Euro","ein Euro","einer Euro","einem Euro"],ans:"einen Euro",hint:"Ohne takes accusative case. What happens to ein with masculine nouns?"},
{type:"fb",s:"Die {1} Leute kaufen hier ein.",a:["meisten"],opts:["meisten","mehr","viel","wenig"],hint:"MOST people shop here. Superlative of viel.",sSrc:"The most people shop here."},
{type:"mc",q:"Hundertdreiundfünfzig = ?",opts:["135","153","351","315"],ans:"153",hint:"hundert=100, dreiundfünfzig=53."},
{type:"drag_fill",s:"{1} Sie bitte {2} den Laden und bezahlen Sie {3} Einkauf!",blanks:{"1":"Gehen","2":"durch","3":"den"},pool:["Gehen","durch","den","Geht","der","das"],hint:"Polite: go through the store and pay for the (masc acc) purchase!",sSrc:"Go please through the store and pay for the purchase!"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-verumius-kitchen",trg:"Verumius steht in seiner Küche. Brot auf dem Tisch, Obst im Kühlschrank, Wein auf dem Regal. Morgen: kochen. Ohne Rezept, ohne Plan, aber mit Mut. Und mit einer Einkaufsliste. Hildi hat ihm eine geschrieben.",src:"Verumius stands in his kitchen. Bread on the table, fruit in the fridge, wine on the shelf. Tomorrow: cooking. Without a recipe, without a plan, but with courage. And with a shopping list. Hildi wrote him one."}
]},

{id:"deu_r4l9",title:"Essen und Trinken",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Essen und Trinken",desc:"The German breakfast table, the Bäckerei, and everything you need to eat and drink your way through daily life.",goals:["Name common German foods and drinks","Use articles with food nouns","Order and shop for food items"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-verumius-breakfast",trg:"Der nächste Morgen. Kaffee, Brötchen, Käse. Verumius frühstückt wie ein Deutscher. Fast. Die Butter fehlt.",src:"The next morning. Coffee, rolls, cheese. Verumius has breakfast like a German. Almost. The butter is missing."},
{type:"teach",trg:"der Kaffee",src:"the coffee",note:"Masculine noun. No plural in standard use. 'Zwei Kaffee, bitte!'",example:"A: Möchtest du Kaffee?\nB: Ja, einen Kaffee mit Milch, bitte.",exampleSrc:"A: Would you like coffee?\nB: Yes, a coffee with milk, please.",funFact:"Germany is the 3rd largest coffee consumer in the world, after Finland and the Netherlands. 'Kaffee und Kuchen' (coffee and cake) at 3 PM is a sacred German tradition."},
{type:"teach",trg:"die Milch",src:"the milk",note:"Feminine noun. No plural. 'Mit Milch' = with milk.",example:"A: Trinken Sie Milch?\nB: Nein, ich trinke keine Milch.",exampleSrc:"A: Do you drink milk?\nB: No, I don't drink milk.",funFact:"German distinguishes: Vollmilch (whole milk), fettarme Milch (low-fat), Magermilch (skim). At the supermarket, the cap color tells you which type."},
{type:"teach",trg:"der Tee",src:"the tea",note:"Masculine noun. Plural: die Tees. 'Schwarzer Tee' = black tea.",example:"A: Möchten Sie Tee oder Kaffee?\nB: Tee, bitte. Grünen Tee.",exampleSrc:"A: Would you like tea or coffee?\nB: Tea, please. Green tea.",funFact:"'Tee' comes from Chinese 'te' via Dutch traders. Northern Germany, especially East Frisia, has a tea culture rivaling England's. They drink more tea per capita than any other German region."},
{type:"teach",trg:"das Bier",src:"the beer",note:"Neuter noun. Plural: die Biere. Germany's national drink.",example:"A: Ein Bier, bitte!\nB: Welches Bier? Pils, Weizen oder Kölsch?",exampleSrc:"A: A beer, please!\nB: Which beer? Pilsner, wheat or Kölsch?",funFact:"Germany has the Reinheitsgebot (Purity Law) from 1516: beer may only contain water, barley, and hops. There are over 1,500 breweries and 5,000 beer brands."},
{type:"teach",trg:"der Wein",src:"the wine",note:"Masculine noun. Plural: die Weine. 'Rotwein' = red, 'Weißwein' = white.",example:"A: Trinken Sie Wein?\nB: Ja, ich mag Weißwein.",exampleSrc:"A: Do you drink wine?\nB: Yes, I like white wine.",funFact:"Germany's wine regions along the Rhine and Mosel produce excellent Riesling. Glühwein (mulled wine) is the star of every Christmas market. 'Wein' and English 'wine' come from Latin 'vinum.'"},
{type:"teach",trg:"das Brötchen",src:"the bread roll",note:"Neuter noun. Plural: die Brötchen. Diminutive of 'Brot' (bread).",example:"A: Ich möchte zwei Brötchen, bitte.\nB: Mit Butter und Käse?",exampleSrc:"A: I'd like two bread rolls, please.\nB: With butter and cheese?",funFact:"Brötchen have different names across Germany: Semmel (Bavaria), Schrippe (Berlin), Wecken (Southwest). Starting a 'what is the correct name' debate is a guaranteed conversation starter."},
{type:"teach",trg:"die Kartoffel",src:"the potato",note:"Feminine noun. Plural: die Kartoffeln.",example:"A: Magst du Kartoffeln?\nB: Ja, Bratkartoffeln sind mein Lieblingsessen!",exampleSrc:"A: Do you like potatoes?\nB: Yes, fried potatoes are my favorite food!",funFact:"Kartoffel comes from Italian 'tartufolo' (truffle), because early potatoes looked like truffles. Frederick the Great forced Prussians to eat them. Now Germany eats 60 kg per person per year."},
{type:"teach",trg:"der Reis",src:"the rice",note:"Masculine noun. No standard plural. 'Reis mit Gemüse' = rice with vegetables.",example:"A: Möchten Sie Reis oder Kartoffeln?\nB: Reis, bitte.",exampleSrc:"A: Would you like rice or potatoes?\nB: Rice, please.",funFact:"'Reis' comes from Greek 'oryza' via Latin. In a German Mensa (university cafeteria), Reis mit Sauce is the cheapest meal option. Every student knows it."},
{type:"teach",trg:"der Salat",src:"the salad",note:"Masculine noun. Plural: die Salate. Also means 'lettuce.'",example:"A: Ich nehme einen Salat.\nB: Einen großen oder kleinen Salat?",exampleSrc:"A: I'll have a salad.\nB: A large or small salad?",funFact:"'Salat' in German can mean the dish (salad) OR the plant (lettuce). 'Kopfsalat' = head lettuce. 'Kartoffelsalat' = potato salad, a German BBQ essential with as many recipes as there are grandmothers."},
{type:"teach",trg:"die Birne",src:"the pear",note:"Feminine noun. Plural: die Birnen. Also slang for 'head.'",example:"A: Möchtest du eine Birne?\nB: Ja, die Birnen sehen gut aus!",exampleSrc:"A: Would you like a pear?\nB: Yes, the pears look good!",funFact:"'Birne' also means 'light bulb' (die Glühbirne = glow-pear) because of the shape. And in slang, 'Birne' means 'head': 'Mir raucht die Birne' = my head is smoking (I'm thinking hard)."},
{type:"teach",trg:"der Kuchen",src:"the cake",note:"Masculine noun. Plural: die Kuchen. German Kuchen is a daily treat.",example:"A: Möchtest du ein Stück Kuchen?\nB: Ja, bitte! Apfelkuchen?",exampleSrc:"A: Would you like a piece of cake?\nB: Yes, please! Apple cake?",funFact:"Kaffee und Kuchen at 3 PM is Germany's unofficial fourth meal. Popular types: Schwarzwälder Kirschtorte (Black Forest cake), Apfelkuchen, Bienenstich (bee sting cake)."},
{type:"teach",trg:"der Fisch",src:"the fish",note:"Masculine noun. Plural: die Fische.",example:"A: Essen Sie gern Fisch?\nB: Ja, besonders Lachs.",exampleSrc:"A: Do you like eating fish?\nB: Yes, especially salmon.",funFact:"Fischbrötchen (fish sandwich) is THE street food of northern Germany, especially Hamburg. It is to Hamburg what the Döner is to Berlin."},
{type:"teach",trg:"das Hähnchen",src:"the chicken (cooked)",note:"Neuter noun. Plural: die Hähnchen. Diminutive of Hahn (rooster).",example:"A: Ich möchte Hähnchen, bitte.\nB: Hähnchen mit Reis oder Pommes?",exampleSrc:"A: I'd like chicken, please.\nB: Chicken with rice or fries?",funFact:"Hähnchen means the cooked dish. A living chicken is 'das Huhn.' A rooster is 'der Hahn.' Half a roasted chicken at Oktoberfest is called 'ein halbes Hendl' in Bavarian."},
{type:"teach",trg:"das Ei",src:"the egg",note:"Neuter noun. Plural: die Eier.",example:"A: Wie möchtest du dein Ei?\nB: Weich gekocht, bitte.",exampleSrc:"A: How would you like your egg?\nB: Soft-boiled, please.",funFact:"The German breakfast egg (Frühstücksei) is serious business. There is even a famous comedy sketch about couples arguing over the perfect egg-boiling time: the '4.5 Minuten Ei' debate."},
{type:"teach",trg:"das Öl",src:"the oil",note:"Neuter noun. Plural: die Öle. Used for cooking and other purposes.",example:"A: Kochst du mit Öl oder Butter?\nB: Mit Olivenöl.",exampleSrc:"A: Do you cook with oil or butter?\nB: With olive oil.",funFact:"'Öl' works in compounds: Olivenöl (olive oil), Sonnenblumenöl (sunflower oil), Motoröl (motor oil). Same word for kitchen and garage."},
{type:"teach",trg:"das Salz",src:"the salt",note:"Neuter noun. No standard plural. Essential in every kitchen.",example:"A: Kannst du mir das Salz geben?\nB: Hier, bitte.",exampleSrc:"A: Can you pass me the salt?\nB: Here you go.",funFact:"Salzburg (salt castle) and the word 'salary' both come from salt. In medieval Germany, salt was so valuable it was called 'weißes Gold' (white gold)."},
{type:"teach",trg:"das Glas",src:"the glass",note:"Neuter noun. Plural: die Gläser (with umlaut!).",example:"A: Kann ich ein Glas Wasser haben?\nB: Hier, ein Glas Wasser.",exampleSrc:"A: Can I have a glass of water?\nB: Here, a glass of water.",funFact:"'Ein Glas Wein,' 'ein Glas Bier,' 'ein Glas Wasser.' German uses 'Glas' like English uses 'glass of.' But 'Gläser' (plural) adds an umlaut. Tricky!"},
{type:"teach",trg:"die Flasche",src:"the bottle",note:"Feminine noun. Plural: die Flaschen.",example:"A: Eine Flasche Wasser, bitte.\nB: Mit oder ohne Kohlensäure?",exampleSrc:"A: A bottle of water, please.\nB: Sparkling or still?",funFact:"Germans LOVE sparkling water. If you ask for 'Wasser' in a restaurant, you will get sparkling. Say 'stilles Wasser' for still water. The Pfand (bottle deposit) system means you return bottles for 25 cents each."},
{type:"mc",q:"Which drink is Germany's most traditional?",opts:["der Tee","die Milch","der Wein","das Bier"],ans:"das Bier",hint:"Think Reinheitsgebot, Oktoberfest, and 1,500 breweries."},
{type:"fb",s:"Zwei {1}, bitte. Mit Butter und Käse.",a:["Brötchen"],opts:["Brötchen","Kuchen","Kartoffeln","Eier"],hint:"These small bread rolls are a breakfast staple at the Bäckerei.",sSrc:"Two bread rolls, please. With butter and cheese."},
{type:"mc",q:"'Kannst du mir das Salz geben?' What does the speaker want?",opts:["The salt","The sugar","A glass","A bottle"],ans:"The salt",hint:"This white seasoning has been called 'white gold' in history."},
{type:"match",pairs:[{trg:"der Kaffee",src:"coffee"},{trg:"die Milch",src:"milk"},{trg:"das Brötchen",src:"bread roll"},{trg:"die Kartoffel",src:"potato"},{trg:"der Fisch",src:"fish"},{trg:"das Ei",src:"egg"}]},
{type:"story",speaker:"verumius",mood:"determined",art:"de-rewe-entrance-return",trg:"Morgen gehe ich wieder. Diesmal mit Münze, mit Tüte, und mit einer Liste. Ich bin bereit. Glaube ich.",src:"Tomorrow I go again. This time with a coin, with a bag, and with a list. I am ready. I think."}
]},

{id:"deu_r4l10",title:"Geld und Maße",icon:"💶",xp:15,board:true,steps:[
{type:"intro",title:"Geld und Maße",desc:"Shopping means numbers. Big numbers. Learn to talk about money, measurements, and everything you need to survive a German supermarket.",goals:["Use large numbers: hundreds, thousands, millions","Name coins, currencies, and measurements","Shop for shoes, jackets, and more"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-verumius-list-writing",trg:"Verumius schreibt eine Liste. Jedes Wort mit Artikel. Der Reis. Die Butter. Das Mehl. Er übt die Preise: drei Euro neunzig. Sieben fünfundsiebzig.",src:"Verumius writes a list. Every word with its article. Der Reis. Die Butter. Das Mehl. He practices the prices: three euros ninety. Seven seventy-five."},
{type:"teach",trg:"der Euro",src:"the euro",note:"Masculine noun. Plural: die Euro (not Euros!). 'Fünf Euro, bitte.'",example:"A: Was kostet das?\nB: Das kostet drei Euro fünfzig.",exampleSrc:"A: How much does that cost?\nB: That costs three euros fifty.",funFact:"Germany switched from the Deutsche Mark to the Euro in 2002. Some older Germans still mentally convert prices to D-Mark. One Euro was 1.95583 DM."},
{type:"teach",trg:"der Cent",src:"the cent",note:"Masculine noun. Plural: die Cent. 100 Cent = 1 Euro.",example:"A: Haben Sie fünfzig Cent?\nB: Nein, nur einen Euro.",exampleSrc:"A: Do you have fifty cents?\nB: No, only a euro.",funFact:"The German 1-Cent coin shows an oak leaf, the 2-Cent shows a Brandenburg Gate. Most Germans want to abolish 1 and 2 Cent coins because they cost more to make than they are worth."},
{type:"teach",trg:"das Konto",src:"the bank account",note:"Neuter noun. Plural: die Konten. From Italian 'conto.'",example:"A: Hast du ein Konto bei der Sparkasse?\nB: Ja, mein Konto ist bei der Sparkasse.",exampleSrc:"A: Do you have an account at Sparkasse?\nB: Yes, my account is at Sparkasse.",funFact:"Germany is still a cash country. Many restaurants and shops do not accept cards. The phrase 'Nur Barzahlung' (cash only) will haunt you. Always carry cash."},
{type:"teach",trg:"einhundert",src:"one hundred (100)",note:"Number. Also simply 'hundert.' 'Einhundert Euro' = 100 euros.",example:"A: Wie viel kostet die Jacke?\nB: Einhundert Euro.",exampleSrc:"A: How much does the jacket cost?\nB: One hundred euros.",funFact:"German numbers get interesting after 20: 'einundzwanzig' (one-and-twenty = 21). The ones digit comes BEFORE the tens. This reversal confuses every English speaker."},
{type:"teach",trg:"zweihundert",src:"two hundred (200)",note:"Number. Pattern: number + hundert. Dreihundert = 300.",example:"A: Wie viel ist die Miete?\nB: Zweihundert Euro pro Zimmer.",exampleSrc:"A: How much is the rent?\nB: Two hundred euros per room.",funFact:"Large German numbers are written as one word: zweihundertfünfunddreißig = 235. This is not a typo. German really does this."},
{type:"teach",trg:"eintausend",src:"one thousand (1000)",note:"Number. Also simply 'tausend.' Pattern: number + tausend.",example:"A: Wie viele Leute wohnen hier?\nB: Eintausend in diesem Haus.",exampleSrc:"A: How many people live here?\nB: One thousand in this building.",funFact:"In German, the dot and comma are swapped: 1.000 = one thousand, 1,5 = one point five. This causes endless confusion with prices and bank transfers."},
{type:"teach",trg:"siebzig",src:"seventy (70)",note:"Number. The 'en' is dropped: sieben → siebt + zig = siebzig.",example:"A: Mein Opa ist siebzig.\nB: Siebzig? Er sieht jung aus!",exampleSrc:"A: My grandpa is seventy.\nB: Seventy? He looks young!",funFact:"'Siebzig' drops the 'en' from 'sieben', unlike 'siebzehn' (17) which also shortens to 'sieb.' The pattern is consistent for 7: sieben → sieb- in compounds.",},
{type:"teach",trg:"die Million",src:"the million",note:"Feminine noun. Plural: die Millionen. 'Eine Million Euro.'",example:"A: Berlin hat drei Millionen Einwohner.\nB: Und München?",exampleSrc:"A: Berlin has three million inhabitants.\nB: And Munich?",funFact:"Unlike English, 'Million' is a noun in German, so it takes an article: 'eine Million.' After eine, it stays singular. After zwei+: 'zwei Millionen' (with -en)."},
{type:"teach",trg:"die Milliarde",src:"the billion (1,000,000,000)",note:"Feminine noun. Plural: die Milliarden. NOT 'Billion' in German!",example:"A: Die Erde hat acht Milliarden Menschen.\nB: Das sind viele Leute!",exampleSrc:"A: Earth has eight billion people.\nB: That is a lot of people!",funFact:"TRAP: German 'Billion' = English 'trillion' (1,000,000,000,000). German 'Milliarde' = English 'billion.' This causes business misunderstandings worth billions (or Milliarden)."},
{type:"teach",trg:"der Grad",src:"the degree",note:"Masculine noun. Plural: die Grade. For temperature and angles.",example:"A: Wie warm ist es?\nB: Zwanzig Grad.",exampleSrc:"A: How warm is it?\nB: Twenty degrees.",funFact:"Germany uses Celsius. 20 Grad = comfortable. 30 Grad = hot (Germans start complaining). 35 Grad = emergency (schools may close). 0 Grad = normal winter."},
{type:"teach",trg:"das Kilo",src:"the kilogram (short form)",note:"Neuter noun. Short for Kilogramm. 'Ein Kilo Äpfel, bitte.'",example:"A: Ein Kilo Kartoffeln, bitte.\nB: Hier, genau ein Kilo.",exampleSrc:"A: A kilo of potatoes, please.\nB: Here, exactly one kilo.",funFact:"At German markets, you buy by the Kilo (or Pfund = 500g). 'Ein halbes Kilo' = half a kilo = 500g. Supermarket scales at the fruit section are self-service."},
{type:"teach",trg:"der Kilometer",src:"the kilometer",note:"Masculine noun. Plural: die Kilometer. Abbreviated: km.",example:"A: Wie weit ist es bis Hamburg?\nB: Dreihundert Kilometer.",exampleSrc:"A: How far is it to Hamburg?\nB: Three hundred kilometers.",funFact:"The German Autobahn has sections with NO speed limit. The recommended speed is 130 km/h, but some drivers go 200+. 'Freie Fahrt für freie Bürger' (free driving for free citizens) is an unofficial motto."},
{type:"teach",trg:"der Zentimeter",src:"the centimeter",note:"Masculine noun. Plural: die Zentimeter. Abbreviated: cm.",example:"A: Wie groß bist du?\nB: Eins achtzig. Hundertachtzig Zentimeter.",exampleSrc:"A: How tall are you?\nB: One eighty. A hundred eighty centimeters.",funFact:"Germans say height in meters: 'eins achtzig' = 1.80m. Not in feet and inches. If someone is 'eins neunzig' (1.90m), they are considered tall."},
{type:"teach",trg:"das Prozent",src:"the percent",note:"Neuter noun. 'Zwanzig Prozent Rabatt' = 20% discount.",example:"A: Wie viel Rabatt gibt es?\nB: Zwanzig Prozent auf alles!",exampleSrc:"A: How much discount is there?\nB: Twenty percent off everything!",funFact:"German stores have two big sale seasons: Sommerschlussverkauf (summer clearance) and Winterschlussverkauf (winter clearance). Discounts of 50-70 Prozent are common."},
{type:"teach",trg:"der Teil",src:"the part / piece",note:"Masculine noun. Plural: die Teile. 'Zum Teil' = partly.",example:"A: Das ist nur ein Teil des Problems.\nB: Und der andere Teil?",exampleSrc:"A: That is only one part of the problem.\nB: And the other part?",funFact:"'Teil' builds many compounds: Stadtteil (city district), Nachteil (disadvantage, literally 'night-part'), Vorteil (advantage, 'fore-part'), Urteil (judgment)."},
{type:"teach",trg:"der Automat",src:"the vending machine / ATM",note:"Masculine noun. Plural: die Automaten. From Greek 'automatos.'",example:"A: Wo ist ein Automat?\nB: Dort drüben, neben der Tür.",exampleSrc:"A: Where is a vending machine?\nB: Over there, next to the door.",funFact:"German train stations have Fahrkartenautomaten (ticket machines) that accept coins, cards, and bills. The interface is available in 10+ languages. They replace most ticket counters."},
{type:"teach",trg:"die Jacke",src:"the jacket",note:"Feminine noun. Plural: die Jacken.",example:"A: Zieh deine Jacke an, es ist kalt!\nB: Ich brauche keine Jacke.",exampleSrc:"A: Put on your jacket, it is cold!\nB: I do not need a jacket.",funFact:"Germans have a saying: 'Es gibt kein schlechtes Wetter, nur schlechte Kleidung.' There is no bad weather, only bad clothing. A good Jacke solves everything."},
{type:"teach",trg:"der Schuh",src:"the shoe",note:"Masculine noun. Plural: die Schuhe. German shoe sizes differ from US/UK.",example:"A: Welche Schuhgröße haben Sie?\nB: Zweiundvierzig.",exampleSrc:"A: What shoe size do you have?\nB: Forty-two.",funFact:"German shoe sizes: 42 = US 9 / UK 8. The system (Pariser Stich) measures in 2/3 cm increments. If someone says 'Schuhgröße 42,' they mean European 42."},
{type:"teach",trg:"die Tasche",src:"the bag / pocket",note:"Feminine noun. Plural: die Taschen. Dual meaning!",example:"A: Hast du eine Tasche?\nB: Ja, meine Tasche ist hier.",exampleSrc:"A: Do you have a bag?\nB: Yes, my bag is here.",funFact:"Tasche = bag AND pocket. 'Hosentasche' = pants pocket. 'Handtasche' = handbag. 'Taschenlampe' = pocket lamp (flashlight). 'Taschenbuch' = pocket book (paperback)."},
{type:"teach",trg:"verkaufen",src:"to sell",note:"Inseparable prefix verb: ich verkaufe, du verkaufst. Opposite: kaufen (buy).",example:"A: Verkaufen Sie auch Briefmarken?\nB: Nein, nur am Schalter.",exampleSrc:"A: Do you also sell stamps?\nB: No, only at the counter.",funFact:"'Ver-' often adds a negative or intensive meaning: kaufen (buy) vs verkaufen (sell). 'Ver-' flips the direction. Similarly: mieten (rent) vs vermieten (rent out)."},
{type:"teach",trg:"zahlen",src:"to pay",note:"Regular verb: ich zahle, du zahlst. 'Ich möchte zahlen' = check please.",example:"A: Ich möchte zahlen, bitte.\nB: Bar oder mit Karte?",exampleSrc:"A: I would like to pay, please.\nB: Cash or card?",funFact:"'Zahlen, bitte!' is how you ask for the check in a German restaurant. The waiter brings a portable card reader or counts change from a wallet. No bill left on the table."},
{type:"teach",trg:"meist",src:"mostly / most",note:"Superlative adverb. 'Meistens' = usually/most of the time.",example:"A: Was isst du meistens zum Frühstück?\nB: Meistens Brötchen mit Käse.",exampleSrc:"A: What do you usually eat for breakfast?\nB: Mostly bread rolls with cheese.",funFact:"'Am meisten' = the most (superlative of viel). 'Meistens' = most of the time. 'Der Meister' = the master. All from the same root."},
{type:"mc",q:"A German says their height is 'eins fünfundachtzig.' How tall are they?",opts:["185 pounds","1.85 feet","1.85 meters","185 kilometers"],ans:"1.85 meters",hint:"Germans use the metric system for height, not feet or pounds."},
{type:"fb",s:"Das kostet {1} Euro fünfzig.",a:["drei"],opts:["drei","der","die","das"],hint:"A number! The price is X euros and fifty cents.",sSrc:"That costs three euros fifty."},
{type:"match",pairs:[{trg:"der Euro",src:"euro"},{trg:"der Cent",src:"cent"},{trg:"das Kilo",src:"kilogram"},{trg:"die Jacke",src:"jacket"},{trg:"der Schuh",src:"shoe"},{trg:"die Tasche",src:"bag"}]},
{type:"story",speaker:"verumius",mood:"confident",art:"de-rewe-entrance-confident",trg:"REWE. Rote Buchstaben. Automatische Türen. Aber diesmal: eine Münze in der Tasche, eine Liste in der Hand, und ein Wort auf den Lippen. 'Guten Tag.'",src:"REWE. Red letters. Automatic doors. But this time: a coin in the pocket, a list in the hand, and a word on the lips. 'Guten Tag.'"}
]}
]};

export default UNIT_4;
